const Theme={LIGHT: 'light',DARK: 'dark',SYSTEM: 'system'};const STORAGE_KEY='mekong-theme-preference';function getStoredTheme(){const stored=localStorage.getItem(STORAGE_KEY);if(stored){return stored;}return window.matchMedia('(prefers-color-scheme: dark)').matches ? Theme.DARK : Theme.LIGHT;}function applyTheme(theme){if(theme===Theme.SYSTEM){const systemDark=window.matchMedia('(prefers-color-scheme: dark)').matches;document.documentElement.setAttribute('data-theme',systemDark ? Theme.DARK : Theme.LIGHT);}else{document.documentElement.setAttribute('data-theme',theme);}const themeColor=document.querySelector('meta[name="theme-color"]');if(themeColor){const color=theme===Theme.DARK ? '#191C1B' : '#006A60';themeColor.setAttribute('content',color);}}function saveTheme(theme){localStorage.setItem(STORAGE_KEY,theme);}function toggleTheme(){const current=document.documentElement.getAttribute('data-theme');const newTheme=current===Theme.DARK ? Theme.LIGHT : Theme.DARK;const toggle=document.querySelector('.theme-toggle');if(toggle){toggle.classList.add('toggling');setTimeout(()=>toggle.classList.remove('toggling'),300);}applyTheme(newTheme);saveTheme(newTheme);window.dispatchEvent(new CustomEvent('themechange',{detail:{theme: newTheme}}));}function initThemeToggle(){let toggle=document.querySelector('.theme-toggle');if(!toggle){toggle=document.createElement('button');toggle.className='theme-toggle';toggle.setAttribute('aria-label','Chuyển đổi chế độ tối/sáng');toggle.innerHTML=`<span class="theme-toggle-icon"><span class="material-symbols-outlined moon-icon" aria-hidden="true">dark_mode</span><span class="material-symbols-outlined sun-icon" aria-hidden="true">light_mode</span></span><span class="theme-toggle-label">Chế độ</span>`;document.body.appendChild(toggle);toggle.addEventListener('click',toggleTheme);}else{toggle.onclick=toggleTheme;}addFloatingToggle();}function addFloatingToggle(){if(window.innerWidth<=768){let floating=document.querySelector('.theme-toggle-floating');if(!floating){floating=document.createElement('button');floating.className='theme-toggle-floating';floating.setAttribute('aria-label','Chuyển chế độ tối');floating.innerHTML=`<span class="material-symbols-outlined moon-icon" aria-hidden="true">dark_mode</span><span class="material-symbols-outlined sun-icon" aria-hidden="true">light_mode</span>`;floating.addEventListener('click',(e)=>{e.stopPropagation();toggleTheme();});document.body.appendChild(floating);}}else{const floating=document.querySelector('.theme-toggle-floating');if(floating)floating.remove();}}function listenForSystemChanges(){const mediaQuery=window.matchMedia('(prefers-color-scheme: dark)');const handler=(e)=>{const stored=localStorage.getItem(STORAGE_KEY);if(!stored||stored===Theme.SYSTEM){applyTheme(Theme.SYSTEM);}};mediaQuery.addEventListener('change',handler);mediaQuery.addListener(handler);}function init(){const theme=getStoredTheme();applyTheme(theme);if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>{initThemeToggle();listenForSystemChanges();});}else{initThemeToggle();listenForSystemChanges();}window.addEventListener('resize',addFloatingToggle);}init();export{toggleTheme,getStoredTheme,Theme,STORAGE_KEY};